scwin.f_Save = async function () {
  //변경사항 확인
  if (ds_330.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, "변경사항이 없습니다."); //변경사항이 없습니다.
    return;
  }
  for (var i = 1; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "sellAmt") + ds_330.getCellData(i, "sellVat") != ds_330.getCellData(i - 1, "sellAmt") + ds_330.getCellData(i - 1, "sellVat")) {
      await $c.win.alert($p, "합계금액이 일치하지 않습니다.");
      return;
    }
  }
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "bilgClntNo") == "") {
      await $c.win.alert($p, "계약정보는 필수 항목입니다.");
      return;
    }
  }
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if ((ds_330.getCellData(i, "pchsClntNo") != "" || ds_330.getCellData(i, "pchsCtrtStDt") != "" || ds_330.getCellData(i, "pchsPchsAmt") != 0 || ds_330.getCellData(i, "pchsVehcl") != "") && ds_330.getCellData(i, "vehclNo") != "" && ds_330.getCellData(i, "vehclArvDt") != "" && ds_330.getCellData(i, "vehclPchsAmt") != 0) {
      await $c.win.alert($p, "배차정보를 입력시 위탁계약정보를 입력할수 없습니다.");
      return;
    }
  }
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if ((ds_330.getCellData(i, "vehclNo") != "" || ds_330.getCellData(i, "vehclArvDt") != "" || ds_330.getCellData(i, "vehclPchsAmt") != 0) && ds_330.getCellData(i, "pchsClntNo") != "" && ds_330.getCellData(i, "pchsCtrtStDt") != "" && ds_330.getCellData(i, "pchsPchsAmt") != 0 && ds_330.getCellData(i, "pchsVehcl") != "") {
      await $c.win.alert($p, "위탁계약정보 입력시 배차정보를 입력할수 없습니다.");
      return;
    }
  }
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "confirmYn") == 1) {
      await $c.win.alert($p, "확정된 화물은 저장할수 없습니다");
      return;
    }
  }
  //하차일 날짜 유효성 확인
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "vehclArvDt") != "") {
      if (!$c.date.isDate($p, ds_330.getCellData(i, "vehclArvDt"))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_018, ["하차일"]);
        return;
      }
    }
  }

  //위탁계약정보_계약기간 from 날짜 유효성 확인
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "pchsCtrtStDt") != "") {
      if (!$c.date.isDate($p, ds_330.getCellData(i, "pchsCtrtStDt"))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_018, ["위탁계약정보_계약기간 from"]);
        return;
      }
    }
  }
  //계약기간 from 은 실적날짜 이전 확인 
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "vehclArvDt") > ds_330.getCellData(i, "rsltsStdDt")) {
      await $c.gus.cfAlertMsg($p, "'하차일' 은 '실적날짜'" + ds_330.getCellData(i, "rsltsStdDt") + "이전으로만 입력가능합니다.");
      return;
    }
  }
  //계약기간 from 은 실적날짜 이전 확인       
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "pchsCtrtStDt") > ds_330.getCellData(i, "rsltsStdDt")) {
      await $c.gus.cfAlertMsg($p, "'위탁계약정보_계약기간 from' 은 '실적날짜': " + ds_330.getCellData(i, "rsltsStdDt") + "이전으로만 입력가능합니다.");
      return;
    }
  }
  //차량번호7~ 9자리 확인            
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "vehclNo") != "") {
      var vehclNoLength = ds_330.getCellData(i, "vehclNo");
      if (vehclNoLength.trim().length < 7) {
        await $c.win.alert($p, "배차정보의 차량등록번호는 7자리 이상입니다.");
        retrun;
      }
      if (vehclNoLength.trim().length > 9) {
        await $c.win.alert($p, "배차정보의 차량등록번호는 9자리 이하입니다.");
        retrun;
      }
    }
  }
  for (var i = 0; i < ds_330.getTotalRow(); i++) {
    if (ds_330.getCellData(i, "pchsVehcl") != "") {
      var pchsVehclLength = ds_330.getCellData(i, "pchsVehcl");
      if (pchsVehclLength.trim().length < 7) {
        await $c.win.alert($p, "위탁계약정보의 차량등록번호는 7자리 이상입니다.");
        retrun;
      }
      if (pchsVehclLength.trim().length > 9) {
        await $c.win.alert($p, "위탁계약정보의 차량등록번호는  9자리 이하입니다.");
        retrun;
      }
    }
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    // 저장 하시겠습니까?
    $c.sbm.execute($p, sbm_save);
  }
};

