scwin.f_Excel = async function () {
  if (ds_330.getTotalRow() == 0) {
    return;
  }
  var fileName = "화물운송실적신고(업로드)";
  var options = {
    fileName: fileName + ".xlsx",
    sheetName: fileName,
    type: 1
  };
  await $c.data.downloadGridViewExcel($p, gr_330, options);
};

